package com.example.sanzinkstore;

import android.graphics.Bitmap;
import android.graphics.BitmapFactory;
import android.net.Uri;
import android.os.Bundle;
import android.text.TextUtils;
import android.util.Log;
import android.view.View;
import android.widget.ArrayAdapter;
import android.widget.Toast;
import androidx.activity.result.ActivityResultLauncher;
import androidx.activity.result.contract.ActivityResultContracts;
import androidx.appcompat.app.AppCompatActivity;
import com.example.sanzinkstore.databinding.ActivityAdminProductBinding;
import com.example.sanzinkstore.model.Product;
import com.google.android.gms.tasks.Task;
import com.google.firebase.firestore.FirebaseFirestore;
import com.squareup.picasso.Picasso;

import org.json.JSONObject;

import java.io.ByteArrayOutputStream;
import java.io.InputStream;
import java.util.concurrent.TimeUnit;

import okhttp3.MediaType;
import okhttp3.MultipartBody;
import okhttp3.OkHttpClient;
import okhttp3.Request;
import okhttp3.RequestBody;
import okhttp3.Response;

public class AdminProductActivity extends AppCompatActivity {

    private static final String TAG = "AdminProductActivity";
    private ActivityAdminProductBinding binding;
    private FirebaseFirestore db;
    private String productId = null;
    private Uri selectedImageUri = null;
    private String currentImageUrl = null;

    // Standard Imgur Client ID
    private static final String IMGUR_CLIENT_ID = "546c25a59c58ad7";

    private final ActivityResultLauncher<String> getContent = registerForActivityResult(
            new ActivityResultContracts.GetContent(),
            uri -> {
                if (uri != null) {
                    selectedImageUri = uri;
                    binding.imagePreview.setImageURI(uri);
                    binding.btnSelectImage.setVisibility(View.GONE);
                    // Clear manual URL if gallery image is selected
                    binding.editImageUrl.setText("");
                }
            }
    );

    @Override
    protected void onCreate(Bundle savedInstanceState) {
        super.onCreate(savedInstanceState);
        binding = ActivityAdminProductBinding.inflate(getLayoutInflater());
        setContentView(binding.getRoot());

        db = FirebaseFirestore.getInstance();

        setupCategoryDropdown();

        if (getIntent().hasExtra("PRODUCT_ID")) {
            productId = getIntent().getStringExtra("PRODUCT_ID");
            loadProductData();
            binding.btnDelete.setVisibility(View.VISIBLE);
        }

        binding.btnSelectImage.setVisibility(View.VISIBLE);
        binding.btnSelectImage.setOnClickListener(v -> getContent.launch("image/*"));
        binding.imagePreview.setOnClickListener(v -> getContent.launch("image/*"));

        binding.btnSave.setOnClickListener(v -> handleSave());

        binding.btnDelete.setOnClickListener(v -> deleteProduct());
    }

    private void setupCategoryDropdown() {
        String[] mainCategories = {"Goods", "Meals", "Beverages"};
        ArrayAdapter<String> mainAdapter = new ArrayAdapter<>(this, android.R.layout.simple_dropdown_item_1line, mainCategories);
        binding.editCategory.setAdapter(mainAdapter);

        binding.editCategory.setOnItemClickListener((parent, view, position, id) -> {
            String selectedMain = mainCategories[position];
            updateSubCategoryDropdown(selectedMain);
        });
    }

    private void updateSubCategoryDropdown(String mainCategory) {
        String[] subCategories;
        switch (mainCategory) {
            case "Goods":
                subCategories = new String[]{"All", "Ramen", "Buldak", "Seaweed", "Teokbokki", "Drinks"};
                break;
            case "Meals":
                subCategories = new String[]{"All", "Buldak", "K-Ramen", "Cheese Ramen", "Samyang Omolette", "Rice Meals", "Stations Specials", "Side Dish"};
                break;
            case "Beverages":
                subCategories = new String[]{"All", "Milktea", "Fruit Soda", "Korean Abrica"};
                break;
            default:
                subCategories = new String[]{"All"};
                break;
        }
        ArrayAdapter<String> subAdapter = new ArrayAdapter<>(this, android.R.layout.simple_dropdown_item_1line, subCategories);
        binding.editSubCategory.setAdapter(subAdapter);
        binding.editSubCategory.setText("All", false); // Default to All
    }

    private void loadProductData() {
        binding.uploadProgress.setVisibility(View.VISIBLE);
        db.collection("products").document(productId).get()
                .addOnSuccessListener(documentSnapshot -> {
                    binding.uploadProgress.setVisibility(View.GONE);
                    Product product = documentSnapshot.toObject(Product.class);
                    if (product != null) {
                        binding.editName.setText(product.getName());
                        binding.editDescription.setText(product.getDescription());
                        binding.editPrice.setText(String.valueOf(product.getPrice()));
                        binding.editCategory.setText(product.getCategory(), false);

                        updateSubCategoryDropdown(product.getCategory());
                        binding.editSubCategory.setText(product.getSubCategory(), false);

                        binding.switchAvailable.setChecked(product.isAvailable());
                        currentImageUrl = product.getImageUrl();
                        binding.editImageUrl.setText(currentImageUrl);
                        if (currentImageUrl != null && !currentImageUrl.isEmpty()) {
                            Picasso.get().load(currentImageUrl).placeholder(R.drawable.ic_food).into(binding.imagePreview);
                            binding.btnSelectImage.setVisibility(View.GONE);
                        }
                    }
                })
                .addOnFailureListener(e -> {
                    binding.uploadProgress.setVisibility(View.GONE);
                    Toast.makeText(this, "Load failed: " + e.getMessage(), Toast.LENGTH_SHORT).show();
                });
    }

    private void handleSave() {
        String name = binding.editName.getText().toString().trim();
        String priceStr = binding.editPrice.getText().toString().trim();
        String category = binding.editCategory.getText().toString().trim();
        String subCategory = binding.editSubCategory.getText().toString().trim();
        String manualUrl = binding.editImageUrl.getText().toString().trim();

        if (TextUtils.isEmpty(name) || TextUtils.isEmpty(priceStr) || TextUtils.isEmpty(category)) {
            Toast.makeText(this, "Please fill required fields (Name, Price, Category)", Toast.LENGTH_SHORT).show();
            return;
        }

        if (selectedImageUri != null) {
            // Upload selected gallery image
            uploadToImgur(selectedImageUri);
        } else if (!TextUtils.isEmpty(manualUrl)) {
            // Use pasted URL
            saveProductToFirestore(manualUrl);
        } else {
            // Use existing URL (might be null for new product)
            saveProductToFirestore(currentImageUrl);
        }
    }

    private void uploadToImgur(Uri uri) {
        binding.btnSave.setEnabled(false);
        binding.uploadProgress.setVisibility(View.VISIBLE);

        new Thread(() -> {
            try {
                InputStream inputStream = getContentResolver().openInputStream(uri);
                Bitmap bitmap = BitmapFactory.decodeStream(inputStream);
                if (bitmap == null) throw new Exception("Failed to decode image");

                // Compress image to ensure it's not too large
                ByteArrayOutputStream outputStream = new ByteArrayOutputStream();
                bitmap.compress(Bitmap.CompressFormat.JPEG, 70, outputStream);
                byte[] imageBytes = outputStream.toByteArray();

                OkHttpClient client = new OkHttpClient.Builder()
                        .connectTimeout(30, TimeUnit.SECONDS)
                        .writeTimeout(30, TimeUnit.SECONDS)
                        .readTimeout(30, TimeUnit.SECONDS)
                        .build();

                RequestBody requestBody = new MultipartBody.Builder()
                        .setType(MultipartBody.FORM)
                        .addFormDataPart("image", "product.jpg",
                                RequestBody.create(imageBytes, MediaType.parse("image/jpeg")))
                        .build();

                Request request = new Request.Builder()
                        .url("https://api.imgur.com/3/image")
                        .header("Authorization", "Client-ID " + IMGUR_CLIENT_ID)
                        .post(requestBody)
                        .build();

                try (Response response = client.newCall(request).execute()) {
                    String responseData = response.body() != null ? response.body().string() : "";
                    Log.d(TAG, "Imgur Response: " + responseData);

                    if (response.isSuccessful()) {
                        JSONObject json = new JSONObject(responseData);
                        String uploadedUrl = json.getJSONObject("data").getString("link");
                        runOnUiThread(() -> saveProductToFirestore(uploadedUrl));
                    } else {
                        throw new Exception("Imgur Error " + response.code() + ": " + response.message());
                    }
                }

            } catch (Exception e) {
                runOnUiThread(() -> {
                    binding.btnSave.setEnabled(true);
                    binding.uploadProgress.setVisibility(View.GONE);
                    Log.e(TAG, "Upload failed", e);
                    Toast.makeText(this, "Upload failed: " + e.getMessage(), Toast.LENGTH_LONG).show();
                });
            }
        }).start();
    }

    private void saveProductToFirestore(String imageUrl) {
        String name = binding.editName.getText().toString().trim();
        String description = binding.editDescription.getText().toString().trim();
        String priceStr = binding.editPrice.getText().toString().trim();
        String category = binding.editCategory.getText().toString().trim();
        String subCategory = binding.editSubCategory.getText().toString().trim();

        if (imageUrl == null) imageUrl = "";

        double price;
        try {
            price = Double.parseDouble(priceStr);
        } catch (NumberFormatException e) {
            Toast.makeText(this, "Invalid price format", Toast.LENGTH_SHORT).show();
            binding.btnSave.setEnabled(true);
            binding.uploadProgress.setVisibility(View.GONE);
            return;
        }

        binding.btnSave.setEnabled(false);
        binding.uploadProgress.setVisibility(View.VISIBLE);

        Product product = new Product(productId, name, description, price, imageUrl, category, subCategory, binding.switchAvailable.isChecked());

        Task<Void> task;
        if (productId == null) {
            // Adding new product
            String id = db.collection("products").document().getId();
            product.setId(id);
            task = db.collection("products").document(id).set(product);
        } else {
            // Updating existing product
            product.setId(productId);
            task = db.collection("products").document(productId).set(product);
        }

        task.addOnSuccessListener(aVoid -> {
            Log.d(TAG, "Product saved successfully");
            Toast.makeText(this, "Product Saved!", Toast.LENGTH_SHORT).show();
            finish();
        }).addOnFailureListener(e -> {
            binding.btnSave.setEnabled(true);
            binding.uploadProgress.setVisibility(View.GONE);
            Log.e(TAG, "Firestore Error", e);
            Toast.makeText(this, "Database Error: " + e.getMessage(), Toast.LENGTH_SHORT).show();
        });
    }

    private void deleteProduct() {
        if (productId != null) {
            binding.uploadProgress.setVisibility(View.VISIBLE);
            db.collection("products").document(productId).delete()
                    .addOnSuccessListener(aVoid -> {
                        Toast.makeText(this, "Product Deleted!", Toast.LENGTH_SHORT).show();
                        finish();
                    })
                    .addOnFailureListener(e -> {
                        binding.uploadProgress.setVisibility(View.GONE);
                        Toast.makeText(this, "Delete failed: " + e.getMessage(), Toast.LENGTH_SHORT).show();
                    });
        }
    }
}

package com.example.sanzinkstore;

import android.graphics.Bitmap;
import android.graphics.BitmapFactory;
import android.net.Uri;
import android.os.Bundle;
import android.text.TextUtils;
import android.util.Log;
import android.view.View;
import android.widget.ArrayAdapter;
import android.widget.Toast;
import androidx.activity.result.ActivityResultLauncher;
import androidx.activity.result.contract.ActivityResultContracts;
import androidx.appcompat.app.AppCompatActivity;
import com.example.sanzinkstore.databinding.ActivityAdminProductBinding;
import com.example.sanzinkstore.model.Product;
import com.google.android.gms.tasks.Task;
import com.google.firebase.firestore.FirebaseFirestore;
import com.squareup.picasso.Picasso;

import org.json.JSONObject;

import java.io.ByteArrayOutputStream;
import java.io.InputStream;
import java.util.concurrent.TimeUnit;

import okhttp3.MediaType;
import okhttp3.MultipartBody;
import okhttp3.OkHttpClient;
import okhttp3.Request;
import okhttp3.RequestBody;
import okhttp3.Response;

public class AdminProductActivity extends AppCompatActivity {

    private static final String TAG = "AdminProductActivity";
    private ActivityAdminProductBinding binding;
    private FirebaseFirestore db;
    private String productId = null;
    private Uri selectedImageUri = null;
    private String currentImageUrl = null;

    // Standard Imgur Client ID
    private static final String IMGUR_CLIENT_ID = "546c25a59c58ad7";

    private final ActivityResultLauncher<String> getContent = registerForActivityResult(
            new ActivityResultContracts.GetContent(),
            uri -> {
                if (uri != null) {
                    selectedImageUri = uri;
                    binding.imagePreview.setImageURI(uri);
                    binding.btnSelectImage.setVisibility(View.GONE);
                    // Clear manual URL if gallery image is selected
                    binding.editImageUrl.setText("");
                }
            }
    );

    @Override
    protected void onCreate(Bundle savedInstanceState) {
        super.onCreate(savedInstanceState);
        binding = ActivityAdminProductBinding.inflate(getLayoutInflater());
        setContentView(binding.getRoot());

        db = FirebaseFirestore.getInstance();

        // Back button on toolbar
        com.google.android.material.appbar.MaterialToolbar toolbar = binding.toolbar;
        setSupportActionBar(toolbar);
        toolbar.setNavigationOnClickListener(v -> finish());

        setupCategoryDropdown();

        if (getIntent().hasExtra("PRODUCT_ID")) {
            productId = getIntent().getStringExtra("PRODUCT_ID");
            loadProductData();
            binding.btnDelete.setVisibility(View.VISIBLE);
        }

        binding.btnSelectImage.setVisibility(View.VISIBLE);
        binding.btnSelectImage.setOnClickListener(v -> getContent.launch("image/*"));
        binding.imagePreview.setOnClickListener(v -> getContent.launch("image/*"));
        
        binding.btnSave.setOnClickListener(v -> handleSave());
        
        binding.btnDelete.setOnClickListener(v -> deleteProduct());
    }

    private void setupCategoryDropdown() {
        String[] mainCategories = {"Goods", "Meals", "Beverages"};
        ArrayAdapter<String> mainAdapter = new ArrayAdapter<>(this, android.R.layout.simple_dropdown_item_1line, mainCategories);
        binding.editCategory.setAdapter(mainAdapter);

        binding.editCategory.setOnItemClickListener((parent, view, position, id) -> {
            String selectedMain = mainCategories[position];
            updateSubCategoryDropdown(selectedMain);
        });
    }

    private void updateSubCategoryDropdown(String mainCategory) {
        String[] subCategories;
        switch (mainCategory) {
            case "Goods":
                subCategories = new String[]{"All", "Ramen", "Buldak", "Seaweed", "Teokbokki", "Drinks"};
                break;
            case "Meals":
                subCategories = new String[]{"All", "Buldak", "K-Ramen", "Cheese Ramen", "Samyang Omolette", "Rice Meals", "Stations Specials", "Side Dish"};
                break;
            case "Beverages":
                subCategories = new String[]{"All", "Milktea", "Fruit Soda", "Korean Abrica"};
                break;
            default:
                subCategories = new String[]{"All"};
                break;
        }
        ArrayAdapter<String> subAdapter = new ArrayAdapter<>(this, android.R.layout.simple_dropdown_item_1line, subCategories);
        binding.editSubCategory.setAdapter(subAdapter);
        binding.editSubCategory.setText("All", false); // Default to All
    }

    private void loadProductData() {
        binding.uploadProgress.setVisibility(View.VISIBLE);
        db.collection("products").document(productId).get()
                .addOnSuccessListener(documentSnapshot -> {
                    binding.uploadProgress.setVisibility(View.GONE);
                    Product product = documentSnapshot.toObject(Product.class);
                    if (product != null) {
                        binding.editName.setText(product.getName());
                        binding.editDescription.setText(product.getDescription());
                        binding.editPrice.setText(String.valueOf(product.getPrice()));
                        binding.editCategory.setText(product.getCategory(), false);
                        
                        updateSubCategoryDropdown(product.getCategory());
                        binding.editSubCategory.setText(product.getSubCategory(), false);
                        
                        binding.switchAvailable.setChecked(product.isAvailable());
                        currentImageUrl = product.getImageUrl();
                        binding.editImageUrl.setText(currentImageUrl);
                        if (currentImageUrl != null && !currentImageUrl.isEmpty()) {
                            Picasso.get().load(currentImageUrl).placeholder(R.drawable.ic_food).into(binding.imagePreview);
                            binding.btnSelectImage.setVisibility(View.GONE);
                        }
                    }
                })
                .addOnFailureListener(e -> {
                    binding.uploadProgress.setVisibility(View.GONE);
                    Toast.makeText(this, "Load failed: " + e.getMessage(), Toast.LENGTH_SHORT).show();
                });
    }

    private void handleSave() {
        String name = binding.editName.getText().toString().trim();
        String priceStr = binding.editPrice.getText().toString().trim();
        String category = binding.editCategory.getText().toString().trim();
        String subCategory = binding.editSubCategory.getText().toString().trim();
        String manualUrl = binding.editImageUrl.getText().toString().trim();

        if (TextUtils.isEmpty(name) || TextUtils.isEmpty(priceStr) || TextUtils.isEmpty(category)) {
            Toast.makeText(this, "Please fill required fields (Name, Price, Category)", Toast.LENGTH_SHORT).show();
            return;
        }

        if (selectedImageUri != null) {
            // Upload selected gallery image
            uploadToImgur(selectedImageUri);
        } else if (!TextUtils.isEmpty(manualUrl)) {
            // Use pasted URL
            saveProductToFirestore(manualUrl);
        } else {
            // Use existing URL (might be null for new product)
            saveProductToFirestore(currentImageUrl);
        }
    }

    private void uploadToImgur(Uri uri) {
        binding.btnSave.setEnabled(false);
        binding.uploadProgress.setVisibility(View.VISIBLE);

        new Thread(() -> {
            try {
                InputStream inputStream = getContentResolver().openInputStream(uri);
                Bitmap bitmap = BitmapFactory.decodeStream(inputStream);
                if (bitmap == null) throw new Exception("Failed to decode image");

                // Compress image to ensure it's not too large
                ByteArrayOutputStream outputStream = new ByteArrayOutputStream();
                bitmap.compress(Bitmap.CompressFormat.JPEG, 70, outputStream);
                byte[] imageBytes = outputStream.toByteArray();

                OkHttpClient client = new OkHttpClient.Builder()
                        .connectTimeout(30, TimeUnit.SECONDS)
                        .writeTimeout(30, TimeUnit.SECONDS)
                        .readTimeout(30, TimeUnit.SECONDS)
                        .build();

                RequestBody requestBody = new MultipartBody.Builder()
                        .setType(MultipartBody.FORM)
                        .addFormDataPart("image", "product.jpg",
                                RequestBody.create(imageBytes, MediaType.parse("image/jpeg")))
                        .build();

                Request request = new Request.Builder()
                        .url("https://api.imgur.com/3/image")
                        .header("Authorization", "Client-ID " + IMGUR_CLIENT_ID)
                        .post(requestBody)
                        .build();

                try (Response response = client.newCall(request).execute()) {
                    String responseData = response.body() != null ? response.body().string() : "";
                    Log.d(TAG, "Imgur Response: " + responseData);

                    if (response.isSuccessful()) {
                        JSONObject json = new JSONObject(responseData);
                        String uploadedUrl = json.getJSONObject("data").getString("link");
                        runOnUiThread(() -> saveProductToFirestore(uploadedUrl));
                    } else {
                        throw new Exception("Imgur Error " + response.code() + ": " + response.message());
                    }
                }

            } catch (Exception e) {
                runOnUiThread(() -> {
                    binding.btnSave.setEnabled(true);
                    binding.uploadProgress.setVisibility(View.GONE);
                    Log.e(TAG, "Upload failed", e);
                    Toast.makeText(this, "Upload failed: " + e.getMessage(), Toast.LENGTH_LONG).show();
                });
            }
        }).start();
    }

    private void saveProductToFirestore(String imageUrl) {
        String name = binding.editName.getText().toString().trim();
        String description = binding.editDescription.getText().toString().trim();
        String priceStr = binding.editPrice.getText().toString().trim();
        String category = binding.editCategory.getText().toString().trim();
        String subCategory = binding.editSubCategory.getText().toString().trim();

        if (imageUrl == null) imageUrl = "";

        double price;
        try {
            price = Double.parseDouble(priceStr);
        } catch (NumberFormatException e) {
            Toast.makeText(this, "Invalid price format", Toast.LENGTH_SHORT).show();
            binding.btnSave.setEnabled(true);
            binding.uploadProgress.setVisibility(View.GONE);
            return;
        }

        binding.btnSave.setEnabled(false);
        binding.uploadProgress.setVisibility(View.VISIBLE);

        Product product = new Product(productId, name, description, price, imageUrl, category, subCategory, binding.switchAvailable.isChecked());

        Task<Void> task;
        if (productId == null) {
            // Adding new product
            String id = db.collection("products").document().getId();
            product.setId(id);
            task = db.collection("products").document(id).set(product);
        } else {
            // Updating existing product
            product.setId(productId);
            task = db.collection("products").document(productId).set(product);
        }

        task.addOnSuccessListener(aVoid -> {
            Log.d(TAG, "Product saved successfully");
            Toast.makeText(this, "Product Saved!", Toast.LENGTH_SHORT).show();
            finish();
        }).addOnFailureListener(e -> {
            binding.btnSave.setEnabled(true);
            binding.uploadProgress.setVisibility(View.GONE);
            Log.e(TAG, "Firestore Error", e);
            Toast.makeText(this, "Database Error: " + e.getMessage(), Toast.LENGTH_SHORT).show();
        });
    }

    private void deleteProduct() {
        if (productId != null) {
            binding.uploadProgress.setVisibility(View.VISIBLE);
            db.collection("products").document(productId).delete()
                    .addOnSuccessListener(aVoid -> {
                        Toast.makeText(this, "Product Deleted!", Toast.LENGTH_SHORT).show();
                        finish();
                    })
                    .addOnFailureListener(e -> {
                        binding.uploadProgress.setVisibility(View.GONE);
                        Toast.makeText(this, "Delete failed: " + e.getMessage(), Toast.LENGTH_SHORT).show();
                    });
        }
    }
}

package com.example.sanzinkstore;

import android.content.Intent;
import android.os.Handler;
import android.os.Looper;
import androidx.activity.OnBackPressedCallback;
import androidx.appcompat.app.ActionBarDrawerToggle;
import androidx.appcompat.app.AppCompatActivity;
import androidx.appcompat.widget.Toolbar;
import androidx.core.view.GravityCompat;
import androidx.drawerlayout.widget.DrawerLayout;
import com.google.android.gms.auth.api.signin.GoogleSignIn;
import com.google.android.gms.auth.api.signin.GoogleSignInOptions;
import com.google.android.material.navigation.NavigationView;
import com.google.firebase.auth.FirebaseAuth;

/**
 * Base activity that provides a navigation drawer (hamburger menu) instead of a back arrow.
 * Extend this for all secondary screens that should use the side drawer navigation.
 *
 * Usage in subclass onCreate (after setContentView):
 *   setupDrawer(toolbar, R.id.nav_xxx);
 */
public abstract class BaseDrawerActivity extends AppCompatActivity {

    public static final String EXTRA_IS_ADMIN = "IS_ADMIN";

    protected DrawerLayout drawerLayout;
    protected NavigationView navigationView;
    protected boolean isAdmin;

    /**
     * Set up the side navigation drawer tied to the given toolbar.
     *
     * @param toolbar      Toolbar already present in the layout (id: toolbar)
     * @param currentNavId R.id.nav_xxx to pre-check in the drawer menu (pass 0 for none)
     */
    protected void setupDrawer(Toolbar toolbar, int currentNavId) {
        isAdmin = getIntent().getBooleanExtra(EXTRA_IS_ADMIN, false);

        drawerLayout   = findViewById(R.id.drawerLayout);
        navigationView = findViewById(R.id.navigationView);

        setSupportActionBar(toolbar);

        ActionBarDrawerToggle toggle = new ActionBarDrawerToggle(
                this, drawerLayout, toolbar, R.string.app_name, R.string.app_name);
        drawerLayout.addDrawerListener(toggle);
        toggle.syncState();

        navigationView.getMenu().clear();
        navigationView.inflateMenu(isAdmin ? R.menu.drawer_menu : R.menu.customer_drawer_menu);
        if (currentNavId != 0) {
            navigationView.setCheckedItem(currentNavId);
        }

        navigationView.setNavigationItemSelectedListener(item -> {
            int id = item.getItemId();
            drawerLayout.closeDrawer(GravityCompat.START);
            // Small delay so the drawer close animation finishes first
            new Handler(Looper.getMainLooper()).postDelayed(() -> handleNavItem(id), 250);
            return true;
        });

        // Handle back gesture: close drawer if open, otherwise go back
        getOnBackPressedDispatcher().addCallback(this, new OnBackPressedCallback(true) {
            @Override
            public void handleOnBackPressed() {
                if (drawerLayout != null && drawerLayout.isDrawerOpen(GravityCompat.START)) {
                    drawerLayout.closeDrawer(GravityCompat.START);
                } else {
                    setEnabled(false);
                    getOnBackPressedDispatcher().onBackPressed();
                }
            }
        });
    }

    @SuppressWarnings("deprecation")
    private void handleNavItem(int id) {
        if (id == R.id.nav_logout) {
            FirebaseAuth.getInstance().signOut();
            GoogleSignInOptions gso = new GoogleSignInOptions.Builder(GoogleSignInOptions.DEFAULT_SIGN_IN)
                    .requestIdToken(getString(R.string.default_web_client_id))
                    .requestEmail()
                    .build();
            GoogleSignIn.getClient(this, gso).signOut().addOnCompleteListener(t -> {
                startActivity(new Intent(this, LoginActivity.class));
                finishAffinity();
            });

        } else if (id == R.id.nav_pos || id == R.id.nav_home) {
            startActivity(new Intent(this, MainActivity.class)
                    .putExtra(EXTRA_IS_ADMIN, isAdmin)
                    .addFlags(Intent.FLAG_ACTIVITY_CLEAR_TOP));

        } else if (id == R.id.nav_profile) {
            if (!(this instanceof ProfileActivity))
                startActivity(new Intent(this, ProfileActivity.class)
                        .putExtra(EXTRA_IS_ADMIN, isAdmin));

        } else if (id == R.id.nav_settings) {
            if (!(this instanceof SettingsActivity))
                startActivity(new Intent(this, SettingsActivity.class)
                        .putExtra(EXTRA_IS_ADMIN, isAdmin));

        } else if (id == R.id.nav_inventory) {
            if (!(this instanceof InventoryActivity))
                startActivity(new Intent(this, InventoryActivity.class)
                        .putExtra(EXTRA_IS_ADMIN, true));

        } else if (id == R.id.nav_logs) {
            if (!(this instanceof LogsActivity))
                startActivity(new Intent(this, LogsActivity.class)
                        .putExtra(EXTRA_IS_ADMIN, true));

        } else if (id == R.id.nav_messages) {
            if (!(this instanceof SellerInboxActivity))
                startActivity(new Intent(this, SellerInboxActivity.class)
                        .putExtra(EXTRA_IS_ADMIN, true));

        } else if (id == R.id.nav_print_orders || id == R.id.nav_download_csv) {
            startActivity(new Intent(this, MainActivity.class)
                    .putExtra(EXTRA_IS_ADMIN, true)
                    .addFlags(Intent.FLAG_ACTIVITY_CLEAR_TOP));
        }
    }
}

package com.example.sanzinkstore;

import android.os.Bundle;
import android.text.TextUtils;
import android.view.MenuItem;
import android.widget.EditText;
import android.widget.ImageButton;
import android.widget.Toast;

import androidx.annotation.NonNull;
import androidx.appcompat.app.AppCompatActivity;
import androidx.appcompat.widget.Toolbar;
import androidx.recyclerview.widget.LinearLayoutManager;
import androidx.recyclerview.widget.RecyclerView;

import com.example.sanzinkstore.adapter.MessageAdapter;
import com.example.sanzinkstore.model.Message;
import com.google.firebase.auth.FirebaseAuth;
import com.google.firebase.auth.FirebaseUser;
import com.google.firebase.firestore.FieldValue;
import com.google.firebase.firestore.FirebaseFirestore;
import com.google.firebase.firestore.Query;
import com.google.firebase.firestore.QueryDocumentSnapshot;

import java.util.ArrayList;
import java.util.HashMap;
import java.util.List;
import java.util.Map;

/**
 * ChatActivity - Used by BOTH customer and seller for 1-on-1 messaging.
 *
 * Extras expected:
 *   EXTRA_IS_SELLER   (boolean) – true if the current user is the seller
 *   EXTRA_CUSTOMER_ID (String)  – the customer's Firebase UID (required for seller)
 *   EXTRA_CUSTOMER_NAME (String)– display name shown in toolbar (required for seller)
 */
public class ChatActivity extends AppCompatActivity {

    public static final String EXTRA_IS_SELLER    = "EXTRA_IS_SELLER";
    public static final String EXTRA_CUSTOMER_ID  = "EXTRA_CUSTOMER_ID";
    public static final String EXTRA_CUSTOMER_NAME = "EXTRA_CUSTOMER_NAME";

    private static final String SELLER_ID = "seller";

    private FirebaseFirestore db;
    private List<Message> messageList;
    private MessageAdapter adapter;
    private RecyclerView rvMessages;
    private EditText etMessage;

    private String conversationId;  // = customer Firebase UID
    private String currentSenderId; // customer UID or "seller"
    private boolean isSeller;

    @Override
    protected void onCreate(Bundle savedInstanceState) {
        super.onCreate(savedInstanceState);
        setContentView(R.layout.activity_chat);

        db = FirebaseFirestore.getInstance();
        isSeller = getIntent().getBooleanExtra(EXTRA_IS_SELLER, false);

        FirebaseUser user = FirebaseAuth.getInstance().getCurrentUser();

        if (isSeller) {
            // Seller opens a specific customer's conversation
            conversationId  = getIntent().getStringExtra(EXTRA_CUSTOMER_ID);
            currentSenderId = SELLER_ID;
        } else {
            // Customer: use their Firebase UID (anonymous or Google)
            if (user == null) {
                Toast.makeText(this, "Not signed in", Toast.LENGTH_SHORT).show();
                finish();
                return;
            }
            conversationId  = user.getUid();
            currentSenderId = user.getUid();
            ensureConversationExists(user);
        }

        // Derive name for toolbar title
        String chatTitle;
        if (isSeller) {
            chatTitle = getIntent().getStringExtra(EXTRA_CUSTOMER_NAME);
            if (chatTitle == null) chatTitle = "Customer";
        } else {
            chatTitle = "Seller";
        }

        // Toolbar
        Toolbar toolbar = findViewById(R.id.toolbar);
        setSupportActionBar(toolbar);
        if (getSupportActionBar() != null) {
            getSupportActionBar().setDisplayHomeAsUpEnabled(true);
            getSupportActionBar().setTitle(chatTitle);
        }

        // RecyclerView
        rvMessages = findViewById(R.id.rvMessages);
        messageList = new ArrayList<>();
        adapter = new MessageAdapter(messageList, currentSenderId);
        LinearLayoutManager layoutManager = new LinearLayoutManager(this);
        layoutManager.setStackFromEnd(true);
        rvMessages.setLayoutManager(layoutManager);
        rvMessages.setAdapter(adapter);

        // Send button
        etMessage = findViewById(R.id.etMessage);
        ImageButton btnSend = findViewById(R.id.btnSend);
        btnSend.setOnClickListener(v -> sendMessage());

        listenToMessages();
        markMessagesAsRead();
    }

    /** Create the conversation document the first time a customer opens the chat. */
    private void ensureConversationExists(FirebaseUser user) {
        // Determine a human-readable name
        String displayName = user.getDisplayName();
        if (displayName == null || displayName.isEmpty()) {
            displayName = "Customer-" + user.getUid().substring(0, 6);
        }
        final String name = displayName;

        db.collection("conversations").document(conversationId)
                .get()
                .addOnSuccessListener(snapshot -> {
                    if (!snapshot.exists()) {
                        Map<String, Object> data = new HashMap<>();
                        data.put("customerId",       conversationId);
                        data.put("customerName",     name);
                        data.put("lastMessage",      "");
                        data.put("lastMessageTime",  System.currentTimeMillis());
                        data.put("unreadBySeller",   0L);
                        data.put("unreadByCustomer", 0L);
                        db.collection("conversations").document(conversationId).set(data);
                    }
                });
    }

    private void listenToMessages() {
        db.collection("conversations")
                .document(conversationId)
                .collection("messages")
                .orderBy("timestamp", Query.Direction.ASCENDING)
                .addSnapshotListener((snapshots, e) -> {
                    if (e != null || snapshots == null) return;
                    messageList.clear();
                    for (QueryDocumentSnapshot doc : snapshots) {
                        Message msg = doc.toObject(Message.class);
                        msg.setId(doc.getId());
                        messageList.add(msg);
                    }
                    adapter.notifyDataSetChanged();
                    if (!messageList.isEmpty()) {
                        rvMessages.scrollToPosition(messageList.size() - 1);
                    }
                });
    }

    private void sendMessage() {
        String text = etMessage.getText() != null
                ? etMessage.getText().toString().trim() : "";
        if (TextUtils.isEmpty(text)) return;

        long now = System.currentTimeMillis();
        Message message = new Message(currentSenderId, text, now);

        db.collection("conversations")
                .document(conversationId)
                .collection("messages")
                .add(message)
                .addOnSuccessListener(ref -> {
                    etMessage.setText("");
                    updateConversationMeta(text, now);
                })
                .addOnFailureListener(e ->
                        Toast.makeText(this, "Send failed: " + e.getMessage(), Toast.LENGTH_SHORT).show());
    }

    private void updateConversationMeta(String lastMsg, long time) {
        Map<String, Object> updates = new HashMap<>();
        updates.put("lastMessage",     lastMsg);
        updates.put("lastMessageTime", time);
        // Increment the OTHER party's unread count
        if (isSeller) {
            updates.put("unreadByCustomer", FieldValue.increment(1));
        } else {
            updates.put("unreadBySeller", FieldValue.increment(1));
        }
        db.collection("conversations").document(conversationId).update(updates);
    }

    private void markMessagesAsRead() {
        String field = isSeller ? "unreadBySeller" : "unreadByCustomer";
        db.collection("conversations").document(conversationId)
                .update(field, 0L);
    }

    @Override
    public boolean onOptionsItemSelected(@NonNull MenuItem item) {
        if (item.getItemId() == android.R.id.home) { finish(); return true; }
        return super.onOptionsItemSelected(item);
    }
}

